/**
 * Production YouTube Upload Implementation
 * This code handles the complete YouTube upload process with proper error handling
 */

// Import required modules (these would need to be available in the n8n environment)
// For production, ensure googleapis is installed: npm install googleapis

const videoData = $input.first().json.videoData;
const accessToken = $input.first().json.accessToken;
const refreshToken = $input.first().json.refreshToken;
const videoUrl = videoData.videoUrl;

// YouTube API configuration
const YOUTUBE_API_URL = 'https://youtube.googleapis.com/upload/youtube/v3/videos';
const METADATA_URL = 'https://www.googleapis.com/youtube/v3/videos';

async function refreshAccessToken(refreshToken) {
  try {
    const response = await $http.request({
      method: 'POST',
      url: 'https://oauth2.googleapis.com/token',
      data: {
        client_id: process.env.GOOGLE_CLIENT_ID,
        client_secret: process.env.GOOGLE_CLIENT_SECRET,
        refresh_token: refreshToken,
        grant_type: 'refresh_token'
      },
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });

    return response.data.access_token;
  } catch (error) {
    throw new Error(`Token refresh failed: ${error.message}`);
  }
}

async function downloadVideo(url) {
  try {
    const response = await $http.request({
      method: 'GET',
      url: url,
      responseType: 'arraybuffer'
    });

    return Buffer.from(response.data);
  } catch (error) {
    throw new Error(`Video download failed: ${error.message}`);
  }
}

async function initiateResumableUpload(accessToken, metadata) {
  try {
    const response = await $http.request({
      method: 'POST',
      url: `${YOUTUBE_API_URL}?uploadType=resumable&part=snippet,status`,
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
        'X-Upload-Content-Type': 'video/mp4'
      },
      data: metadata
    });

    return response.headers['location'];
  } catch (error) {
    throw new Error(`Upload initiation failed: ${error.message}`);
  }
}

async function uploadVideoChunk(uploadUrl, videoBuffer, accessToken) {
  try {
    const response = await $http.request({
      method: 'PUT',
      url: uploadUrl,
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'video/mp4',
        'Content-Length': videoBuffer.length.toString()
      },
      data: videoBuffer,
      maxContentLength: Infinity,
      maxBodyLength: Infinity,
      timeout: 300000 // 5 minutes timeout
    });

    return response.data;
  } catch (error) {
    if (error.response && error.response.status === 308) {
      // Resume incomplete upload
      throw new Error('Upload incomplete - implement resume logic');
    }
    throw new Error(`Video upload failed: ${error.message}`);
  }
}

// Main execution
try {
  // Check if we have valid connection data
  if (!$input.first().json.hasValidConnection) {
    return {
      json: {
        success: false,
        error: 'No valid YouTube connection found',
        uploadStatus: 'failed'
      }
    };
  }

  // Prepare video metadata
  const metadata = {
    snippet: {
      title: videoData.title.substring(0, 100), // YouTube title limit
      description: `${videoData.description}\n\n#Shorts #Trending #Viral`,
      tags: videoData.tags || ['shorts', 'trending', 'viral'],
      categoryId: '24', // Entertainment category
      defaultLanguage: 'en',
      defaultAudioLanguage: 'en'
    },
    status: {
      privacyStatus: 'public',
      selfDeclaredMadeForKids: false,
      embeddable: true,
      publicStatsViewable: true
    }
  };

  // Try to refresh token if needed
  let currentAccessToken = accessToken;
  if (refreshToken) {
    try {
      currentAccessToken = await refreshAccessToken(refreshToken);
    } catch (tokenError) {
      console.log('Token refresh failed, using existing token:', tokenError.message);
    }
  }

  // Download the video file
  console.log('Downloading video from:', videoUrl);
  const videoBuffer = await downloadVideo(videoUrl);
  console.log('Video downloaded, size:', videoBuffer.length, 'bytes');

  // Initiate resumable upload
  console.log('Initiating YouTube upload...');
  const uploadUrl = await initiateResumableUpload(currentAccessToken, metadata);
  console.log('Upload URL obtained:', uploadUrl ? 'Success' : 'Failed');

  // Upload the video
  console.log('Uploading video to YouTube...');
  const uploadResponse = await uploadVideoChunk(uploadUrl, videoBuffer, currentAccessToken);
  console.log('Upload completed:', uploadResponse);

  // Extract video ID from response
  const videoId = uploadResponse.id;
  const videoPublicUrl = `https://youtube.com/shorts/${videoId}`;

  return {
    json: {
      success: true,
      videoId: videoId,
      videoUrl: videoPublicUrl,
      uploadStatus: 'completed',
      metadata: {
        title: metadata.snippet.title,
        description: metadata.snippet.description,
        privacy: metadata.status.privacyStatus
      }
    }
  };

} catch (error) {
  console.error('YouTube upload error:', error);

  return {
    json: {
      success: false,
      error: error.message,
      uploadStatus: 'failed',
      errorDetails: {
        stack: error.stack,
        timestamp: new Date().toISOString()
      }
    }
  };
}
